export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  // Handlers stored per event name.
  private readonly handlers: {
    [K in keyof TEvents]?: Array<(...args: TEvents[K]) => void>;
  } = {};

  /**
   * Register a handler for an event.
   *
   * @param name    Event name – must be a key of `TEvents`.
   * @param handler Function whose parameters exactly match the tuple type
   *                defined for that event in `TEvents`.
   */
  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const list = this.handlers[name];
    if (list) {
      list.push(handler);
    } else {
      // Initialise the array for this event name.
      this.handlers[name] = [handler];
    }
  }

  /**
   * Emit an event, invoking all registered handlers in registration order.
   *
   * @param name Event name – must be a key of `TEvents`.
   * @param args Arguments that match the tuple type for this event.
   */
  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const list = this.handlers[name];
    if (!list) return;
    for (const handler of list) {
      // The spread args are guaranteed to match the handler signature.
      handler(...args);
    }
  }
}

