class BinaryHeap {
    private data: number[] = [];

    /**
     * @param compare Returns true if `a` has higher priority than `b`.
     */
    constructor(private readonly compare: (a: number, b: number) => boolean) {}

    size(): number {
        return this.data.length;
    }

    peek(): number | undefined {
        return this.data[0];
    }

    push(value: number): void {
        this.data.push(value);
        this.bubbleUp(this.data.length - 1);
    }

    pop(): number | undefined {
        if (this.data.length === 0) return undefined;
        const top = this.data[0];
        const last = this.data.pop()!;
        if (this.data.length > 0) {
            this.data[0] = last;
            this.bubbleDown(0);
        }
        return top;
    }

    private bubbleUp(idx: number): void {
        const arr = this.data;
        while (idx > 0) {
            const parentIdx = Math.floor((idx - 1) / 2);
            // If parent already has higher priority, stop.
            if (this.compare(arr[parentIdx], arr[idx])) break;
            // Otherwise swap with parent.
            [arr[parentIdx], arr[idx]] = [arr[idx], arr[parentIdx]];
            idx = parentIdx;
        }
    }

    private bubbleDown(idx: number): void {
        const arr = this.data;
        const n = arr.length;

        while (true) {
            const leftIdx = 2 * idx + 1;
            const rightIdx = 2 * idx + 2;
            let bestIdx = idx;

            if (leftIdx < n && !this.compare(arr[bestIdx], arr[leftIdx])) {
                bestIdx = leftIdx;
            }
            if (rightIdx < n && !this.compare(arr[bestIdx], arr[rightIdx])) {
                bestIdx = rightIdx;
            }

            if (bestIdx === idx) break;

            [arr[idx], arr[bestIdx]] = [arr[bestIdx], arr[idx]];
            idx = bestIdx;
        }
    }
}

